// Parse HTML and extract key content
const cheerio = require('cheerio');
const crypto = require('crypto');

const html = $input.first()?.body || '';
const $ = cheerio.load(html);

// Extract main content areas
const title = $('title').text().trim();
const h1 = $('h1').map((i, el) => $(el).text().trim()).get().join(' | ');
const pricing = $('*:contains("$"), *:contains("price"), *:contains("plan")').map((i, el) => $(el).text().trim()).get().slice(0, 5);
const features = $('*:contains("feature"), *:contains("benefit")').map((i, el) => $(el).text().trim()).get().slice(0, 10);

// Create content hash for change detection
const contentString = [title, h1, ...pricing, ...features].join('');
const contentHash = crypto.createHash('md5').update(contentString).digest('hex');

// Get URL and competitor name
const url = $('$node["Fetch competitor content"].json.url');
const competitorName = $('$node["Set competitor URLs"].json.competitor_names[$node["Set competitor URLs"].json.current_index]');

return {
  url: url,
  competitor_name: competitorName,
  title: title,
  headings: h1,
  pricing_mentions: pricing,
  feature_mentions: features,
  content_hash: contentHash,
  extracted_at: new Date().toISOString(),
  raw_html: html.substring(0, 5000) // Truncate for storage
};

// Compare with previous content hash from Notion
// This is a simplified version - in practice, you'd query Notion first

const currentData = $input.first();
const currentHash = currentData.content_hash;

// Simulate previous hash lookup (replace with actual Notion query)
const simulatedPreviousHash = 'abc123def456'; // This would come from Notion

const hasChanges = currentHash !== simulatedPreviousHash;

return {
  ...currentData,
  has_changes: hasChanges,
  previous_hash: simulatedPreviousHash,
  change_detected_at: hasChanges ? new Date().toISOString() : null
};

