// Determine if this change warrants immediate Slack notification
const analysis = $node['Analyze competitor changes'].json.response;
const competitor = $json.competitor_name;
const url = $json.url;

// Define trigger keywords for urgent notifications
const urgentKeywords = ['price', 'pricing', 'launch', 'feature', 'acquisition', 'funding', 'partnership'];
const analysisText = analysis.toLowerCase();

const isUrgent = urgentKeywords.some(keyword => analysisText.includes(keyword));

if (isUrgent) {
  return {
    should_notify: true,
    slack_message: `🚨 *Important competitor update detected*\n\n**Competitor:** ${competitor}\n**URL:** ${url}\n**Summary:** ${analysis}\n\n_Automated scan at ${new Date().toLocaleString()}_`,
    analysis: analysis,
    competitor: competitor
  };
} else {
  return {
    should_notify: false,
    reason: 'Minor changes detected, not urgent'
  };
}

// Generate weekly summary report from all competitor data
// This simplified version creates a basic report structure

const allData = $input.all();
const competitors = [...new Set(allData.map(item => item.competitor_name))].filter(Boolean);
const totalChanges = allData.filter(item => item.has_changes).length;
const scanDate = new Date().toLocaleDateString();

const summaryReport = {
  report_title: `Weekly Competitive Intelligence Report - ${scanDate}`,
  summary: {
    competitors_monitored: competitors.length,
    changes_detected: totalChanges,
    scan_date: scanDate
  },
  competitor_details: competitors.map(comp => {
    const compData = allData.filter(item => item.competitor_name === comp);
    const hasChanges = compData.some(item => item.has_changes);
    return {
      name: comp,
      urls_scanned: compData.length,
      changes_detected: hasChanges,
      last_analysis: compData[0]?.extracted_at || 'N/A'
    };
  }),
  recommendations: [
    'Continue monitoring pricing page changes',
    'Focus on feature announcement tracking',
    'Consider expanding monitoring to include blog posts'
  ]
};

// Convert to email-friendly format
const emailBody = `
# ${summaryReport.report_title}

## Summary
- Competitors monitored: ${summaryReport.summary.competitors_monitored}
- Changes detected this week: ${summaryReport.summary.changes_detected}
- Scan date: ${summaryReport.summary.scan_date}

## Competitor Activity
${summaryReport.competitor_details.map(comp => 
  `**${comp.name}**: ${comp.changes_detected ? '⚠️ Changes detected' : '✅ No significant changes'} (${comp.urls_scanned} pages scanned)`
).join('\n')}

## Recommendations
${summaryReport.recommendations.map(rec => `- ${rec}`).join('\n')}

---
*This report was generated automatically by your competitive intelligence workflow.*
`;

return {
  email_subject: `Weekly Competitive Intelligence Report - ${scanDate}`,
  email_body: emailBody,
  report_data: summaryReport
};
